        countCharacters(args) {
            const text = Cast.toString(args.text);
            const char = Cast.toString(args.char);
            
            if (!char) return '0';
            
            let count = 0;
            for (let i = 0; i < text.length; i++) {
                if (text[i] === char) {
                    count++;
                }
            }
            
            return count.toString();
        }

